
public class Exam_01 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub 
		// 표준(콘솔) 입출력
		System.out.print("Hello \tWorld!"); // 줄 바꿈 없음
		System.out.println();
		System.out.print("Hello \nWorld!"); // 줄 바꿈 없음
		System.out.print("\n"); // 줄 바꿈 없음		
		System.out.println("HelloWorld!"); // 자동 줄바꿈 ln은 new line의 약어다.
		System.out.print("HelloWorld!\n"); // 위와 동일하게 출력된다. \n은 줄바꿈이다.(특수목적용이다)
		

//		\n-> 줄바꿈, \t -> tab키와 동일(8칸 스페이스다.) 
	}
	
}